sql:
SELECT COUNT(*) AS comparison_count
FROM comparisons
WHERE filtered_by = 'V2';

SELECT pathway_id, term_name, category, description
FROM pathways
WHERE category = 'metabolic';

SELECT AVG(p_value) AS average_p_value
FROM comparison_pathway_results
WHERE pathway_id = 1;

SELECT COUNT(*) AS pathway_count
FROM comparison_pathway_results
WHERE effect = 'decrease' AND adjusted_p_value < 0.05;

SELECT curator, date
FROM pathway_curation
WHERE pathway_id = 1;

SELECT experiment_type, COUNT(*) AS number_of_comparisons
FROM comparisons
GROUP BY experiment_type;

SELECT COUNT(*) AS pathway_count
FROM pathways
WHERE domain = 'keg';

SELECT COUNT(DISTINCT pathway_id) AS pathway_count
FROM comparison_pathway_results
WHERE effect = 'decrease';

external_knowledge:
- 'Guiding stars' metaphorically refers to pathways in biological or medical research;
- 'Shine the brightest' refers to pathways having the lowest adjusted p-values, indicating significant statistical relevance;
- 'Firmament' is a metaphor for the database comparison being queried (comparison_id = 1);
- 'Luminaries' metaphorically refer to significant pathways;
- 'Luminosity' is a metaphor for the statistical significance represented by the adjusted p-value.

